+func TestSnapshotAcceptsNoNetwork(t *testing.T) {
+	repo := t.TempDir()
+	write(t, repo, "auth.py", "def validate_token(token):\n    return bool(token)\n")
+
+	cwd, err := os.Getwd()
+	if err != nil {
+		t.Fatal(err)
+	}
+	if err := os.Chdir(repo); err != nil {
+		t.Fatal(err)
+	}
+	t.Cleanup(func() {
+		if err := os.Chdir(cwd); err != nil {
+			t.Fatalf("restore cwd: %v", err)
+		}
+	})
+
