16	type Options struct {
17		Version string
18		Env     EntireEnv
19		Stdout  io.Writer
20		Stderr  io.Writer
21	}
22	
23	func Execute(version string, args []string) error {
24		return Run(context.Background(), Options{
25			Version: version,
26			Env:     EnvFromOS(),
27			Stdout:  os.Stdout,
28			Stderr:  os.Stderr,
29		}, args)
30	}
31	
32	func Run(ctx context.Context, opts Options, args []string) error {
33		if opts.Version == "" {
34			opts.Version = "dev"
35		}
36		if opts.Stdout == nil {
37			opts.Stdout = io.Discard
38		}
39		if opts.Stderr == nil {
40			opts.Stderr = io.Discard
41		}
42	
43		if len(args) == 0 {
44			printHelp(opts.Stdout)
45			return nil
46		}
47	
48		switch args[0] {
49		case "diff":
50			return runDiff(ctx, opts, args[1:])
51		case "commit":
52			return runCommit(ctx, opts, args[1:])
53		case "checkpoint":
54			return runCheckpoint(ctx, opts, args[1:])
55		case "analyze":
56			return runAnalyze(ctx, opts, args[1:])
57		case "doctor":
58			return runDoctor(ctx, opts, args[1:])
59		case "capabilities":
60			return runCapabilities(opts, args[1:])
61		case "snapshot":
62			return runProviderRecords(ctx, opts, args[1:], "snapshot")
63		case "symbols":
64			return runProviderRecords(ctx, opts, args[1:], "symbols")
65		case "edges":
66			return runProviderRecords(ctx, opts, args[1:], "edges")
67		case "version", "--version", "-v":
68			if len(args) > 1 && args[1] == "--json" {
69				return json.NewEncoder(opts.Stdout).Encode(map[string]string{
70					"provider": sem.ProviderName,
71					"version":  opts.Version,
72				})
73			}
74			fmt.Fprintln(opts.Stdout, opts.Version)
75			return nil
76		case "help", "--help", "-h":
77			printHelp(opts.Stdout)
78			return nil
79		default:
80			return fmt.Errorf("unknown command %q", args[0])
81		}
82	}
83	
84	func printHelp(out io.Writer) {
85		fmt.Fprintln(out, `entire-sem adds entity-level context to Entire checkpoints.
86	
87	Usage:
88	  entire sem commit [rev] [--json] [--repo path]
89	  entire sem checkpoint <checkpoint-id> [--json] [--repo path]
90	  entire sem diff --base <rev> --head <rev> [--json] [--repo path] [-- path...]
91	  entire sem analyze [--base <rev>] [--head <rev>] [--json] [--repo path] [-- path...]
92	  entire sem doctor [--json]
93	  entire sem version [--json]
94	  entire sem capabilities --json
95	  entire sem snapshot --repo . --format ndjson
96	  entire sem symbols --repo . --format ndjson
97	  entire sem edges --repo . --format ndjson`)
98	}
99	
100	func runDoctor(ctx context.Context, opts Options, args []string) error {
101		asJSON := len(args) == 1 && args[0] == "--json"
102		if len(args) > 1 || (len(args) == 1 && !asJSON) {
103			return errors.New("doctor accepts only --json")
104		}
105		report := map[string]any{
106			"provider":  sem.ProviderName,
107			"version":   opts.Version,
108			"no_egress": true,
109			"environment": map[string]string{
110				envCLIVersion:    valueOrUnset(opts.Env.CLIVersion),
111				envRepoRoot:      valueOrUnset(opts.Env.RepoRoot),
112				envPluginDataDir: valueOrUnset(opts.Env.PluginDataDir),
113			},
114			"phase_1_local_only": map[string]bool{
115				"fetch_remote_code":              false,
116				"download_grammars_or_assets":    false,
117				"upload_telemetry":               false,
118				"call_hosted_model_apis":         false,
119				"call_remote_embedding_provider": false,
120				"perform_network_discovery":      false,
121			},
122		}
123		if !asJSON {
124			fmt.Fprintf(opts.Stdout, "ENTIRE_CLI_VERSION=%s\n", valueOrUnset(opts.Env.CLIVersion))
125			fmt.Fprintf(opts.Stdout, "ENTIRE_REPO_ROOT=%s\n", valueOrUnset(opts.Env.RepoRoot))
126			fmt.Fprintf(opts.Stdout, "ENTIRE_PLUGIN_DATA_DIR=%s\n", valueOrUnset(opts.Env.PluginDataDir))
127			fmt.Fprintln(opts.Stdout, "no_egress=true")
128		}
129	
130		if opts.Env.PluginDataDir != "" {
131			if err := os.MkdirAll(opts.Env.PluginDataDir, 0o700); err != nil {
132				return fmt.Errorf("create plugin data dir: %w", err)
133			}
134			probe, err := os.CreateTemp(opts.Env.PluginDataDir, ".write-test-*")
135			if err != nil {
136				return fmt.Errorf("write plugin data dir: %w", err)
137			}
138			probeName := probe.Name()
139			if err := probe.Close(); err != nil {
140				return fmt.Errorf("close plugin data probe: %w", err)
141			}
142			if err := os.Remove(probeName); err != nil {
143				return fmt.Errorf("remove plugin data probe: %w", err)
144			}
145			report["plugin_data_dir"] = "writable"
146			if !asJSON {
147				fmt.Fprintln(opts.Stdout, "plugin_data_dir=writable")
148			}
149		}
150	
151		repo, err := resolveRepo(ctx, opts.Env, "")
152		if err != nil {
153			report["repo_root"] = ""
154			report["repo_error"] = err.Error()
155			if asJSON {
156				return json.NewEncoder(opts.Stdout).Encode(report)
157			}
158			fmt.Fprintf(opts.Stdout, "repo_root=%s\n", valueOrUnset(""))
159			fmt.Fprintf(opts.Stdout, "repo_error=%s\n", err)
160			return nil
161		}
162		report["repo_root"] = repo
163		if asJSON {
164			return json.NewEncoder(opts.Stdout).Encode(report)
165		}
166		fmt.Fprintf(opts.Stdout, "repo_root=%s\n", repo)
167		return nil
168	}
169	
170	func runCapabilities(opts Options, args []string) error {
171		if len(args) != 1 || args[0] != "--json" {
172			return errors.New("capabilities requires --json")
173		}
174		return json.NewEncoder(opts.Stdout).Encode(sem.Capabilities())
175	}
176	
177	func runProviderRecords(ctx context.Context, opts Options, args []string, mode string) error {
178		flags, rest, err := parseProviderFlags(args)
179		if err != nil {
180			return err
181		}
182		if len(rest) != 0 {
183			return fmt.Errorf("%s received unexpected arguments: %s", mode, strings.Join(rest, " "))
184		}
185		if flags.Format != "ndjson" {
186			return fmt.Errorf("%s requires --format ndjson", mode)
187		}
188		repo, err := resolveRepo(ctx, opts.Env, flags.Repo)
189		if err != nil {
190			return err
191		}
192		snapshot, err := sem.BuildProviderSnapshotWithOptions(ctx, repo, opts.Version, sem.ProviderSnapshotOptions{
193			NoNetwork: flags.NoNetwork,
194			Worktree:  flags.Worktree,
195		})
196		if err != nil {
197			return err
198		}
199		switch mode {
200		case "snapshot":
201			return sem.WriteSnapshotNDJSON(opts.Stdout, snapshot)
202		case "symbols":
203			return sem.WriteSymbolsNDJSON(opts.Stdout, snapshot)
204		case "edges":
205			return sem.WriteRelationsNDJSON(opts.Stdout, snapshot)
206		default:
207			return fmt.Errorf("unknown provider record mode %q", mode)
208		}
209	}
210	
211	type commonFlags struct {
212		Repo string
213		JSON bool
214	}
215	
216	type providerFlags struct {
217		Repo      string
218		Format    string
219		NoNetwork bool
220		Worktree  bool
221	}
222	
223	func parseProviderFlags(args []string) (providerFlags, []string, error) {
224		flags := providerFlags{Format: "ndjson"}
225		var rest []string
226		for i := 0; i < len(args); i++ {
227			switch args[i] {
228			case "--repo":
229				i++
230				if i >= len(args) {
231					return flags, nil, errors.New("--repo requires a value")
232				}
233				flags.Repo = args[i]
234			case "--format":
235				i++
236				if i >= len(args) {
237					return flags, nil, errors.New("--format requires a value")
238				}
239				flags.Format = args[i]
240			case "--no-network":
241				flags.NoNetwork = true
242			case "--worktree":
243				flags.Worktree = true
244			default:
245				rest = append(rest, args[i])
246			}
247		}
248		return flags, rest, nil
249	}
250	
251	func parseCommonFlags(args []string) (commonFlags, []string, error) {
252		var flags commonFlags
253		var rest []string
254		for i := 0; i < len(args); i++ {
255			arg := args[i]
256			switch arg {
257			case "--json":
258				flags.JSON = true
259			case "--repo":
260				i++
261				if i >= len(args) {
262					return flags, nil, errors.New("--repo requires a value")
263				}
264				flags.Repo = args[i]
265			case "--":
266				rest = append(rest, args[i+1:]...)
267				return flags, rest, nil
268			default:
269				rest = append(rest, arg)
270			}
271		}
272		return flags, rest, nil
273	}
274	
275	func runCommit(ctx context.Context, opts Options, args []string) error {
276		flags, rest, err := parseCommonFlags(args)
277		if err != nil {
278			return err
279		}
280		rev := "HEAD"
281		if len(rest) > 0 {
282			rev = rest[0]
283		}
284		if len(rest) > 1 {
285			return errors.New("commit accepts at most one revision")
286		}
287		repo, err := resolveRepo(ctx, opts.Env, flags.Repo)
288		if err != nil {
289			return err
290		}
291		base, err := gitutil.FirstParent(ctx, repo, rev)
292		if err != nil {
293			return err
294		}
295		return analyzeAndPrint(ctx, opts.Stdout, repo, base, rev, nil, flags.JSON)
296	}
297	
298	func runCheckpoint(ctx context.Context, opts Options, args []string) error {
299		flags, rest, err := parseCommonFlags(args)
300		if err != nil {
301			return err
302		}
303		if len(rest) != 1 {
304			return errors.New("checkpoint requires exactly one checkpoint ID")
305		}
306		repo, err := resolveRepo(ctx, opts.Env, flags.Repo)
307		if err != nil {
308			return err
309		}
310		result, err := sem.AnalyzeCheckpoint(ctx, repo, rest[0])
311		if err != nil {
312			return err
313		}
314		return printResult(opts.Stdout, result, flags.JSON)
315	}
316	
317	func runAnalyze(ctx context.Context, opts Options, args []string) error {
318		return runDiff(ctx, opts, args)
319	}
320	
321	func runDiff(ctx context.Context, opts Options, args []string) error {
322		flags, rest, err := parseCommonFlags(args)
323		if err != nil {
324			return err
325		}
326	
327		base := "HEAD~1"
328		head := "HEAD"
329		var paths []string
330		for i := 0; i < len(rest); i++ {
331			switch rest[i] {
332			case "--base":
333				i++
334				if i >= len(rest) {
335					return errors.New("--base requires a value")
336				}
337				base = rest[i]
338			case "--head":
339				i++
340				if i >= len(rest) {
341					return errors.New("--head requires a value")
342				}
343				head = rest[i]
344			default:
345				paths = append(paths, rest[i])
346			}
347		}
348	
349		repo, err := resolveRepo(ctx, opts.Env, flags.Repo)
350		if err != nil {
351			return err
352		}
353		return analyzeAndPrint(ctx, opts.Stdout, repo, base, head, paths, flags.JSON)
354	}
355	
356	func resolveRepo(ctx context.Context, env EntireEnv, explicit string) (string, error) {
357		if explicit != "" {
